// base64 编码
export function encodeUnicode2Base64(str: string) {
    return window.btoa(
        encodeURIComponent(str).replace(/%([\dA-F]{2})/g, (_match, p1) =>
            String.fromCodePoint(Number.parseInt(`0x${p1}`, 16)),
        ),
    );
}

// base64 解码
export function decodeBase642Unicode(str: string)  {
    return decodeURIComponent(
        [...window.atob(str)]
            // eslint-disable-next-line unicorn/prefer-code-point
            .map((c) => `%${`00${c.charCodeAt(0).toString(16)}`.slice(-2)}`)
            .join(''),
    );
}
